class Solution {
    public int minSteps(String s, String t) {
        int[] dp = new int[26];
        for (int i = 0; i < s.length(); i++) {
            char c1 = s.charAt(i);
            char c2 = t.charAt(i);
            dp[c1 - 'a'] = Math.min(dp[c1 - 'a'], dp[c2 - 'a'] + 1);
        }
        return dp[t.charAt(0) - 'a'];
    }
}
```

